from __future__ import annotations

# AUTO-GENERATED MATCHER SHIM (REQ-003-007)
# Matcher: Bash(git commit*|git ci*)
# Generated by build/scripts/generate_hooks.py (REQ-003-007).
# DO NOT EDIT BY HAND - regenerated on every build. Apply NO-REGEN
# sentinel ("# NO-REGEN" or sidecar .noregen) to opt out.
import os as _os
import sys as _sys
import io as _io
import json as _json
import re as _re
import fnmatch as _fnmatch

_MATCHER = 'Bash(git commit*|git ci*)'

# Cap stdin read so a malicious or buggy upstream cannot OOM the shim
# (CWE-400). Mirrors push_guard_base.MAX_STDIN_BYTES (1 MiB) with a
# small headroom; real Claude/Copilot tool_input commands are well
# below this limit. The cap belongs at the SHIM layer because the
# shim reads stdin BEFORE delegating to the wrapped script. Without
# it, the wrapped script's own cap is applied too late: the OOM has
# already happened.
_SHIM_MAX_STDIN_BYTES = 2 * 1024 * 1024


def _shim_classify(pattern):
    # MIRROR: classify_matcher (build-time, build/scripts/generate_hooks.py)
    # and _shim_classify (runtime, this inlined copy) MUST agree on the
    # grammar. Update both when the grammar changes.
    if pattern.startswith("^") and pattern.endswith("$"):
        return "regex", {"pattern": pattern}
    m = _re.match(r"^([A-Za-z_][A-Za-z0-9_]*)\((.*)\)$", pattern)
    if m:
        return "tool-glob", {"toolName": m.group(1), "argsGlob": m.group(2)}
    return "bare", {"toolName": pattern}


def _shim_normalize_args(tool_args):
    r"""Stringify and whitespace-normalize tool_input for fnmatch comparison.

    REQ-003-007: collapse \s+ to a single space and strip ends. Pattern
    is NOT normalized; authors write patterns assuming single spaces.
    """
    if isinstance(tool_args, dict):
        # Bash hooks place command under "command"; keep this fallback
        # path narrow but correct for the live corpus.
        cmd = tool_args.get("command")
        if isinstance(cmd, str):
            text = cmd
        else:
            text = _json.dumps(tool_args, sort_keys=True)
    elif isinstance(tool_args, str):
        text = tool_args
    elif tool_args is None:
        text = ""
    else:
        text = str(tool_args)
    return _re.sub(r"\s+", " ", text).strip()


def _shim_glob_match(args_glob, tool_args_norm):
    """Match args_glob against tool_args_norm with `|` as alternation.

    fnmatch treats `|` as a literal. Authors expect Claude semantics
    where each `|` branch is a separate glob alternation. Split on
    top-level `|` and OR-fold the results.
    """
    branches = args_glob.split("|") if args_glob else [""]
    for branch in branches:
        if _fnmatch.fnmatchcase(tool_args_norm, branch):
            return True
    return False


def _shim_should_fire(payload):
    kind, params = _shim_classify(_MATCHER)
    # Support both VS Code-compatible snake_case (PascalCase event names)
    # and native camelCase (camelCase event names) payloads.
    # Copilot CLI sends snake_case when the event key is PascalCase,
    # camelCase when the event key is camelCase. See issue #2290.
    tool_name = payload.get("tool_name")
    if tool_name is None:
        tool_name = payload.get("toolName")
    if not isinstance(tool_name, str):
        raise ValueError("hook input missing string `tool_name`/`toolName` field")
    if kind == "regex":
        return _re.fullmatch(params["pattern"], tool_name) is not None
    if kind == "tool-glob":
        if tool_name != params["toolName"]:
            return False
        tool_args = payload.get("tool_input")
        if tool_args is None:
            tool_args = payload.get("toolArgs")
        # camelCase payloads send toolArgs as a JSON string, not a parsed
        # object. Parse it so _shim_normalize_args can extract "command".
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError as exc:
                # Host sent a string that is not valid JSON. Log so
                # the operator can diagnose; fall through to normalize
                # which treats raw strings as-is (glob may not match).
                print(
                    "matcher-shim [{}]: toolArgs is not valid JSON: {}".format(
                        _MATCHER, exc
                    ),
                    file=_sys.stderr,
                )
        norm_args = _shim_normalize_args(tool_args)
        return _shim_glob_match(params["argsGlob"], norm_args)
    # bare
    return tool_name == params["toolName"]


def _shim_replay_bytes(payload, raw):
    replay = dict(payload)
    changed = False
    tool_name = replay.get("tool_name")
    if tool_name is None and isinstance(replay.get("toolName"), str):
        replay["tool_name"] = replay["toolName"]
        changed = True
    tool_input = replay.get("tool_input")
    if tool_input is None and "toolArgs" in replay:
        tool_args = replay.get("toolArgs")
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError:
                pass
        replay["tool_input"] = tool_args
        changed = True
    if not changed:
        return raw
    return _json.dumps(replay, separators=(",", ":")).encode("utf-8")


def _shim_dispatch():
    try:
        _raw = _sys.stdin.buffer.read(_SHIM_MAX_STDIN_BYTES + 1)
    except Exception as exc:  # pragma: no cover - defensive
        print(
            "matcher-shim [{}]: failed to buffer stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if len(_raw) > _SHIM_MAX_STDIN_BYTES:
        print(
            "matcher-shim [{}]: stdin exceeds {} bytes; refusing".format(
                _MATCHER, _SHIM_MAX_STDIN_BYTES
            ),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        payload = _json.loads(_raw or b"{}")
    except _json.JSONDecodeError as exc:
        print(
            "matcher-shim [{}]: malformed JSON on stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        fire = _shim_should_fire(payload)
    except Exception as exc:
        print(
            "matcher-shim [{}]: dispatch error: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if _os.environ.get("COPILOT_HOOK_DEBUG"):
        kind, _ = _shim_classify(_MATCHER)
        _sys.stderr.write(
            "matcher-shim [{}]: kind={} fired={}\n".format(_MATCHER, kind, fire)
        )
    if not fire:
        _sys.exit(0)
    # Replay a canonical payload into a fresh stdin so wrapped hooks enforce
    # the same schema even when the host sent the camelCase variant.
    _replay = _shim_replay_bytes(payload, _raw)
    _sys.stdin = _io.TextIOWrapper(_io.BytesIO(_replay), encoding="utf-8")
    rc = _original_main(_replay)
    if rc is None:
        rc = 0
    _sys.exit(int(rc))


# END MATCHER SHIM

def _original_main(stdin_bytes):
    # original script body begins below
    #!/usr/bin/env python3
    """Block git commit when prompt/command/skill behavioral changes lack eval evidence.

    Claude Code PreToolUse hook that enforces ADR-057: Prompt Behavioral Evaluation.
    When staged files include prompt, command, or skill definition changes, checks
    for eval evidence before allowing the commit.

    Evidence sources (any one satisfies the gate):
        1. Eval results file exists: .agents/eval-results/<date>-*.json
        2. Staged eval results alongside the prompt change
        3. SKIP_PROMPT_EVAL=1 environment variable (with justification)

    Hook Type: PreToolUse
    Matcher: Bash(git commit*)
    Exit Codes (Claude Hook Semantics):
        0 = Always (uses JSON decision payload for deny/allow semantics)
    """


    import json
    import os
    import re
    import subprocess
    import sys
    from datetime import UTC, datetime
    from pathlib import Path

    # Bootstrap: find lib directory via env var or manifest walk-up.
    # CLAUDE_PLUGIN_ROOT honored when set; otherwise walk up from __file__
    # looking for .claude-plugin/plugin.json (the plugin marker). Sibling
    # lib/ is the plugin's lib dir. Layout-independent: works in source
    # tree (.claude/) and in the deeper src/<provider>/hooks/<event>/ copy.
    _plugin_root = os.environ.get("CLAUDE_PLUGIN_ROOT")
    if _plugin_root:
        _lib_dir = str(Path(_plugin_root).resolve() / "lib")
    else:
        _cur = Path(__file__).resolve().parent
        _lib_dir = None
        while True:
            if (_cur / ".claude-plugin" / "plugin.json").is_file():
                _lib_dir = str(_cur / "lib")
                break
            if _cur.parent == _cur:
                break
            _cur = _cur.parent
    if _lib_dir is None or not os.path.isdir(_lib_dir):
        print(f"Plugin lib directory not found: {_lib_dir} (CLAUDE_PLUGIN_ROOT={_plugin_root!r})", file=sys.stderr)
        sys.exit(2)
    if _lib_dir not in sys.path:
        sys.path.insert(0, _lib_dir)

    from hook_utilities import get_project_directory, is_git_commit_command  # noqa: E402
    from hook_utilities.guards import skip_if_consumer_repo  # noqa: E402

    _EVAL_FRESHNESS_HOURS = 24

    # Patterns for files that require behavioral eval per ADR-057
    _PROMPT_PATTERNS = [
        re.compile(r"^\.claude/commands/.*\.md$"),
        re.compile(r"^\.github/prompts/.*\.md$"),
        re.compile(r"^\.agents/security/prompts/.*\.md$"),
        re.compile(r"^src/copilot-cli/docs/.*\.md$"),
    ]

    _AGENT_PATTERNS = [
        re.compile(r"^\.claude/agents/(?!CLAUDE\.md|README\.md|INDEX\.md).*\.md$"),
        re.compile(r"^src/claude/(?!CLAUDE\.md|README\.md|AGENTS\.md)(?!.*\.template\.).*\.md$"),
        # Narrowed after #2052 moved agents to src/copilot-cli/agents/. The
        # prior pattern (`^src/copilot-cli/.*\.(?:md|agent\.md)$`) matched
        # every markdown file under the plugin tree, including generated
        # mirrors at src/copilot-cli/instructions/ and src/copilot-cli/skills/
        # that are mechanical regenerator output with no authored prompt
        # content. The eval gate is for behavioral changes to authored
        # agent prompts and authored plugin docs only.
        #
        # Authored paths under src/copilot-cli/:
        #   - agents/*.agent.md (agent prompts; moved here in #2052)
        #   - docs/*.md         (copilot-instructions.md and other plugin docs)
        # Mirror paths NOT matched (mechanical regenerator output):
        #   instructions/, skills/, lib/, hooks/
        re.compile(r"^src/copilot-cli/agents/.*\.agent\.md$"),
        re.compile(r"^src/copilot-cli/docs/.*\.md$"),
        re.compile(r"^src/vs-code-agents/.*\.md$"),
    ]

    _SKILL_PATTERNS = [
        re.compile(r"^\.claude/skills/.*/SKILL\.md$"),
    ]

    # Security-critical paths (ADR-057: stricter tier)
    _SECURITY_CRITICAL_PATTERNS = [
        re.compile(r"security", re.IGNORECASE),
        re.compile(r"pr-quality-gate-security"),
    ]


    def get_staged_files() -> list[str]:
        """Get list of staged file paths."""
        result = subprocess.run(
            ["git", "diff", "--cached", "--name-only"],
            capture_output=True, text=True, timeout=10, check=True,
        )
        return result.stdout.strip().splitlines() if result.stdout.strip() else []


    def classify_staged_behavioral(files: list[str]) -> dict[str, list[str]]:
        """Classify staged files into behavioral change categories."""
        classified: dict[str, list[str]] = {"prompts": [], "agents": [], "skills": []}

        for f in files:
            matched = False
            for pattern in _PROMPT_PATTERNS:
                if pattern.match(f):
                    classified["prompts"].append(f)
                    matched = True
                    break
            if matched:
                continue
            for pattern in _AGENT_PATTERNS:
                if pattern.match(f):
                    classified["agents"].append(f)
                    matched = True
                    break
            if matched:
                continue
            for pattern in _SKILL_PATTERNS:
                if pattern.match(f):
                    classified["skills"].append(f)
                    break

        return classified


    def has_eval_evidence(project_dir: str, staged_files: list[str]) -> bool:
        """Check for behavioral eval evidence.

        Sources:
        1. Eval results file from today in .agents/eval-results/
        2. Staged eval results JSON files
        3. Eval output files in scripts/eval/
        """
        today = datetime.now(tz=UTC).strftime("%Y-%m-%d")

        # Check 1: Eval results directory
        eval_dir = Path(project_dir) / ".agents" / "eval-results"
        if eval_dir.is_dir():
            try:
                results = list(eval_dir.glob(f"{today}-*.json"))
                if results:
                    return True
            except OSError:
                pass

        # Check 2: Staged eval results
        for f in staged_files:
            if "eval" in f.lower() and f.endswith(".json"):
                return True

        # Check 3: Recent eval output in scripts/eval/
        eval_output_dir = Path(project_dir) / "scripts" / "eval"
        if eval_output_dir.is_dir():
            try:
                for result_file in eval_output_dir.glob("*.json"):
                    stat = result_file.stat()
                    age_hours = (
                        datetime.now(tz=UTC).timestamp() - stat.st_mtime
                    ) / 3600
                    if age_hours < _EVAL_FRESHNESS_HOURS:
                        return True
            except OSError:
                pass

        return False


    def is_security_critical(files: list[str]) -> bool:
        """Check if any matched files are security-critical."""
        for f in files:
            for pattern in _SECURITY_CRITICAL_PATTERNS:
                if pattern.search(f):
                    return True
        return False


    def main() -> int:
        """Main hook entry point."""
        if skip_if_consumer_repo("prompt-eval-gate"):
            return 0

        # Bypass: environment variable
        if os.environ.get("SKIP_PROMPT_EVAL") == "1":
            return 0

        try:
            if sys.stdin.isatty():
                return 0

            input_json = sys.stdin.read()
            if not input_json.strip():
                return 0

            input_data = json.loads(input_json)
            tool_input = input_data.get("tool_input")
            if not isinstance(tool_input, dict):
                return 0

            command = tool_input.get("command", "")
            if not is_git_commit_command(command):
                return 0

            staged = get_staged_files()
            if not staged:
                return 0

            classified = classify_staged_behavioral(staged)
            behavioral_files = (
                classified["prompts"] + classified["agents"] + classified["skills"]
            )

            if not behavioral_files:
                return 0

            project_dir = get_project_directory()
            if has_eval_evidence(project_dir, staged):
                return 0

            # Behavioral files staged without eval evidence
            security_tag = ""
            if is_security_critical(behavioral_files):
                security_tag = " [SECURITY-CRITICAL: requires 5 runs, 100% pass]"

            file_list = "\n".join(f"  - {f}" for f in behavioral_files)
            category_summary = []
            if classified["prompts"]:
                category_summary.append(f"{len(classified['prompts'])} prompt(s)")
            if classified["agents"]:
                category_summary.append(f"{len(classified['agents'])} agent(s)")
            if classified["skills"]:
                category_summary.append(f"{len(classified['skills'])} skill(s)")

            output = {
                "decision": "deny",
                "reason": (
                    f"ADR-057 PROMPT EVAL GATE: Behavioral evaluation required "
                    f"before committing {', '.join(category_summary)}.{security_tag}\n\n"
                    f"Matched files:\n{file_list}\n\n"
                    "Run the eval suite:\n"
                    "  python3 scripts/eval/eval-suite.py\n\n"
                    "Or run targeted prompt eval:\n"
                    "  python3 scripts/eval/eval-prompt-change.py "
                    "--prompt <file> --scenarios <scenarios.json> --base-ref main\n\n"
                    "Bypass: Set SKIP_PROMPT_EVAL=1 (document justification in PR)"
                ),
            }
            print(json.dumps(output, separators=(",", ":")))
            return 0

        except Exception as exc:
            # Fail-open for this gate (eval infrastructure may not be set up)
            print(
                f"Prompt eval gate warning: {type(exc).__name__} - {exc}",
                file=sys.stderr,
            )
            return 0
    return main()

_shim_dispatch()
